// Package schema for the UUID-PK example. Demonstrates that entpoly
// emits the right strconv flavour (uuid.Parse) and import line
// (github.com/google/uuid) when parents and the child use uuid.UUID
// primary keys.
package schema

import (
	"time"

	"entgo.io/ent"
	"entgo.io/ent/schema/field"
	"github.com/google/uuid"
)

// Document is a polymorphic parent with a UUID primary key. Any
// Annotation can attach to it via the polymorphic relation declared
// on Annotation. Demonstrates that the back-ref / resolver code
// generated by entpoly handles non-int PKs.
type Document struct{ ent.Schema }

func (Document) Fields() []ent.Field {
	return []ent.Field{
		field.UUID("id", uuid.UUID{}).Default(uuid.New),
		field.String("title"),
		// updated_at exists so Touch() has something to bump.
		field.Time("updated_at").Default(time.Now).UpdateDefault(time.Now),
	}
}
